var (
	expirationFile = ".entropy_timestamp"
	expirationTime time.Time
)

func initExpirationTime() {
	// 🛡️ PERSISTENT COUNTDOWN (Checks if a timestamp already exists, else sets a 72-hour entropy window)
	if _, err := os.Stat(expirationFile); err == nil {
		content, err := os.ReadFile(expirationFile)
		if err == nil {
			parsed, err := time.Parse(time.RFC3339, strings.TrimSpace(string(content)))
			if err == nil {
				expirationTime = parsed
				return
			}
		}
	}

	// Default: July 5, 2026, 11:59pm PHT
	expirationTime = time.Date(2026, time.July, 5, 15, 59, 0, 0, time.UTC)
	_ = os.WriteFile(expirationFile, []byte(expirationTime.Format(time.RFC3339)), 0644)
}

func getStatus() StatusResponse {
	return StatusResponse{
		ExpirationTime: expirationTime.Format(time.RFC3339),
		IsExpired:      time.Now().After(expirationTime),
	}
}

func main() {
	initExpirationTime()

	mux := http.NewServeMux()

	// Static Assets
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/" {
			http.NotFound(w, r)
			return
		}
		http.ServeFile(w, r, "index.html")
	})

	mux.HandleFunc("/styles.css", func(w http.ResponseWriter, r *http.Request) {
		http.ServeFile(w, r, "styles.css")
	})

	mux.HandleFunc("/app.js", func(w http.ResponseWriter, r *http.Request) {
		http.ServeFile(w, r, "app.js")
	})

	// API: Get Countdown/Entropy status
	mux.HandleFunc("/api/entropy-status", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")
		status := getStatus()
		json.NewEncoder(w).Encode(status)
	})

	// API: Fetch Encrypted Letter by Auth Hash
	mux.HandleFunc("/api/letter", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/json")

		// 1. Check Expiration
		status := getStatus()
		if status.IsExpired {
			w.WriteHeader(http.StatusGone) // 410 Gone
			json.NewEncoder(w).Encode(map[string]string{"error": "ENTROPY_REACHED: Data registers have been purged."})
			return
		}

		if r.Method != http.MethodGet {
			w.WriteHeader(http.StatusMethodNotAllowed)
			return
		}

		authKeyHex := strings.ToLower(strings.TrimSpace(r.URL.Query().Get("id")))
		if authKeyHex == "" {
			w.WriteHeader(http.StatusBadRequest)
			json.NewEncoder(w).Encode(map[string]string{"error": "Missing key identifier."})
			return
		}

		encLetter, found := database[authKeyHex]
		if !found {
			w.WriteHeader(http.StatusNotFound) // 404 Not Found
			json.NewEncoder(w).Encode(map[string]string{"error": "Invalid cryptographic key identifier."})
			return
		}

		// Success: Return only the encrypted envelope
		json.NewEncoder(w).Encode(encLetter)
	})

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}

	// Print Audit Banner (Brutalist style)
	fmt.Println("🛡️  PROJECT:FINALITY DAEMON ACTIVE")
	fmt.Println("---------------------------------")
	fmt.Printf("🌌 Bind Address : http://localhost:%s\n", port)
	fmt.Printf("⏳ Entropy Limit : %s\n", expirationTime.Format("2006-01-02 15:04:05 MST"))
	fmt.Printf("🔒 Secure Roles  : %d accounts indexed\n", len(database))
	fmt.Println("---------------------------------")
	fmt.Println("[SYSTEM] Ready to receive auth queries...")

	// Strictly reject/redirect unencrypted HTTP in production, allowing loopback development
	httpsEnforcer := func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			host := r.Host
			isLocal := strings.HasPrefix(host, "localhost:") || strings.HasPrefix(host, "127.0.0.1:") || host == "localhost" || host == "127.0.0.1" || host == "[::1]"

			if !isLocal {
				proto := r.Header.Get("X-Forwarded-Proto")
				if proto == "http" || (r.TLS == nil && proto == "") {
					if r.Method == http.MethodGet {
						http.Redirect(w, r, "https://"+r.Host+r.URL.Path, http.StatusMovedPermanently)
						return
					}
					w.WriteHeader(http.StatusForbidden)
					w.Write([]byte("403 Forbidden: Unencrypted HTTP is strictly rejected. Use HTTPS."))
					return
				}
			}
			next.ServeHTTP(w, r)
		})
	}

	err := http.ListenAndServe(":"+port, httpsEnforcer(mux))
	if err != nil {
		log.Fatalf("❌ Server failed to start: %v", err)
	}
}
